SELECT wf_process_instance.*
FROM wf_process_instance
JOIN wf_history ON wf_process_instance.id = wf_history.process_instance_id
WHERE 1=1


    AND (
        wf_process_instance.creator_id = #{userId} OR
        wf_process_instance.current_user_id = #{userId} OR
        wf_history.user_id = #{userId} OR
        wf_process_instance.executor_id = #{userId}
    )



    AND wf_process_instance.creator_id = #{creatorId}



    AND wf_process_instance.process_id = #{processId}



    AND wf_process_instance.form_id = #{formId}



    AND wf_process_instance.form_group = #{formGroup}



    AND wf_process_instance.form_type = #{formType}



    AND wf_process_instance.status = #{status}



    AND wf_process_instance.name like concat('%', #{name}, '%')



    AND wf_process_instance.creator like concat('%', #{creator}, '%')



    AND wf_process_instance.executor like concat('%', #{executor}, '%')



    AND wf_process_instance.current_user_name like concat('%', #{currentUserName}, '%')



    AND wf_process_instance.current_user_id = #{currentId}



    And wf_process_instance.org_id = #{orgId}


GROUP BY wf_process_instance.id
ORDER BY wf_process_instance.id DESC

SELECT wf_process_instance.*
FROM wf_process_instance
WHERE 1=1


    AND (
    wf_process_instance.`status` NOT IN ("CLOSE_REJECTED", "CLOSE_APPROVED")
    AND wf_process_instance.current_step_id IN (
    SELECT step_id
    FROM wf_process_step_approval
    WHERE user_id = #{userId}
    )
    AND wf_process_instance.id NOT IN (
    SELECT instance_id
    FROM wf_process_instance_step
    WHERE user_id = #{userId}
    )
    )


    AND wf_process_instance.creator_id = #{creatorId}


    AND wf_process_instance.process_id = #{processId}



    AND wf_process_instance.form_id = #{formId}



    AND wf_process_instance.form_group = #{formGroup}



    AND wf_process_instance.form_type = #{formType}



    AND wf_process_instance.status = #{status}



    AND wf_process_instance.name like concat('%', #{name}, '%')



    AND wf_process_instance.creator like concat('%', #{creator}, '%')



    AND wf_process_instance.executor like concat('%', #{executor}, '%')




    And wf_process_instance.org_id = #{orgId}


GROUP BY wf_process_instance.id
ORDER BY wf_process_instance.id DESC

select t_virtual_form.entity_id from  wf_process_step
left join t_virtual_form on t_virtual_form.`code` = wf_process_step.virtual_form_code
where wf_process_step.id = #{currentId}

select t_virtual_form.* from  wf_process_step
left join t_virtual_form on t_virtual_form.`code` = wf_process_step.virtual_form_code
where wf_process_step.id = #{currentId}
